import Navbar from "@/app/components/Navbar";
import Footer from "@/app/components/Footer";
import { prisma } from "@/lib/prisma";
import Link from "next/link";
import SearchBar from "@/app/components/SearchBar";

export default async function CompaniesPage({
    searchParams,
}: {
    searchParams: Promise<{ q?: string }>;
}) {
    const params = await searchParams;

    // Fake or fetch list of companies with jobs count
    const companies = await prisma.company.findMany({
        where: {
            ...(params.q ? { name: { contains: params.q, mode: "insensitive" } } : {}),
        },
        include: { _count: { select: { jobs: { where: { status: "ACTIVE" } } } } },
        orderBy: { createdAt: "desc" },
    }).catch(() => []); // Fallback when DB is unreachable

    return (
        <div style={{ minHeight: "100vh", display: "flex", flexDirection: "column" }}>
            <Navbar />

            <div style={{ background: "var(--page-header-bg)", borderBottom: "1.5px solid var(--border)", padding: "3rem 0 4rem" }}>
                <div className="container-xl" style={{ textAlign: "center", maxWidth: "800px" }}>
                    <h1 style={{ fontSize: "clamp(2rem, 4vw, 2.5rem)", fontWeight: 800, color: "var(--text)", marginBottom: "1.25rem" }}>
                        Khám phá các công ty hàng đầu
                    </h1>
                    <p style={{ fontSize: "1.125rem", color: "var(--text-muted)", marginBottom: "2rem" }}>
                        Tra cứu thông tin, môi trường làm việc và tin tuyển dụng từ hàng ngàn doanh nghiệp.
                    </p>
                    <SearchBar size="lg" />
                </div>
            </div>

            <main className="section-md" style={{ flex: 1, background: "var(--bg)" }}>
                <div className="container-xl">
                    <div style={{ marginBottom: "2rem" }}>
                        <h2 style={{ fontSize: "1.25rem", fontWeight: 700 }}>
                            Danh sách công ty {params.q && `kết quả cho "${params.q}"`}
                        </h2>
                    </div>

                    {companies.length === 0 ? (
                        <div className="card" style={{ padding: "4rem", textAlign: "center", color: "var(--text-muted)" }}>
                            <svg width="48" height="48" fill="none" stroke="var(--border)" strokeWidth="1.5" viewBox="0 0 24 24" style={{ margin: "0 auto 1rem" }}>
                                <path strokeLinecap="round" strokeLinejoin="round" d="M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16m14 0h2m-2 0h-5m-9 0H3m2 0h5M9 7h1m-1 4h1m4-4h1m-1 4h1m-5 10v-5a1 1 0 011-1h2a1 1 0 011 1v5m-4 0h4" />
                            </svg>
                            <p style={{ fontWeight: 600 }}>Không tìm thấy công ty phù hợp</p>
                        </div>
                    ) : (
                        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(300px, 1fr))", gap: "1.5rem" }}>
                            {companies.map((company) => (
                                <Link key={company.id} href={`/companies/${company.slug}`} style={{ textDecoration: "none", color: "inherit", display: "block" }}>
                                    <div className="card" style={{ padding: "1.5rem", height: "100%", transition: "all 0.2s", cursor: "pointer" }}>
                                        <div style={{ display: "flex", gap: "1rem", marginBottom: "1rem" }}>
                                            <div style={{ width: "64px", height: "64px", borderRadius: "12px", background: "var(--tag-bg)", border: "1.5px solid var(--border)", display: "flex", alignItems: "center", justifyContent: "center", fontSize: "1.5rem", fontWeight: 800, color: "var(--primary)" }}>
                                                {company.name.charAt(0)}
                                            </div>
                                            <div>
                                                <h3 style={{ fontSize: "1.125rem", fontWeight: 700, color: "var(--text)", marginBottom: "0.25rem", display: "flex", alignItems: "center", gap: "0.5rem" }}>
                                                    {company.name}
                                                    {company.verified && (
                                                        <svg width="16" height="16" fill="#16A34A" viewBox="0 0 24 24"><path d="M9 16.17L4.83 12l-1.42 1.41L9 19 21 7l-1.41-1.41z" /></svg>
                                                    )}
                                                </h3>
                                                {company.industry && (
                                                    <div style={{ fontSize: "0.875rem", color: "var(--text-muted)" }}>{company.industry}</div>
                                                )}
                                            </div>
                                        </div>
                                        <div style={{ display: "flex", gap: "1rem", fontSize: "0.8125rem", color: "var(--text-muted)", flexWrap: "wrap", marginTop: "1rem" }}>
                                            {company.location && (
                                                <div style={{ display: "flex", alignItems: "center", gap: "0.375rem" }}>
                                                    <svg width="14" height="14" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" /><path strokeLinecap="round" strokeLinejoin="round" d="M15 11a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
                                                    {company.location}
                                                </div>
                                            )}
                                            <div style={{ display: "flex", alignItems: "center", gap: "0.375rem", color: "var(--primary)", fontWeight: 600 }}>
                                                <svg width="14" height="14" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" d="M21 13.255A23.931 23.931 0 0112 15c-3.183 0-6.22-.62-9-1.745M16 6V4a2 2 0 00-2-2h-4a2 2 0 00-2 2v2m4 6h.01M5 20h14a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z" /></svg>
                                                {company._count.jobs} việc làm
                                            </div>
                                        </div>
                                    </div>
                                </Link>
                            ))}
                        </div>
                    )}
                </div>
            </main>

            <Footer />
        </div>
    );
}
